{
  "learning_outcomes": [
    {
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry",
      "topic": "Nature and Measurement in Chemistry",
      "outcomes": [
        "Understand nature of matter, properties, measurement, and uncertainty in measurement."
      ]
    },
    {
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry",
      "topic": "Atomic Masses and Chemical Laws",
      "outcomes": [
        "Apply laws of chemical combination and Dalton's atomic theory to calculate atomic/molecular masses."
      ]
    },
    {
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry",
      "topic": "Stoichiometry",
      "outcomes": [
        "Perform stoichiometric calculations using mole concept and percentage composition."
      ]
    },
    {
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom",
      "topic": "Atomic Models Evolution",
      "outcomes": [
        "Trace the discovery of sub-atomic particles and evolution from Bohr's model to Quantum Mechanical Model."
      ]
    },
    {
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties",
      "topic": "Periodic Classification Genesis",
      "outcomes": [
        "Understand the genesis of periodic classification and modern periodic law."
      ]
    },
    {
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure",
      "topic": "Bonding Theories Application",
      "outcomes": [
        "Apply Kossel-Lewis approach, VSEPR theory, Valence Bond Theory, and Molecular Orbital Theory."
      ]
    },
    {
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics",
      "topic": "Chemical Phenomena Representation",
      "outcomes": [
        "Apply concepts of calorimetry, Gibbs energy change, and equilibrium conditions."
      ]
    },
    {
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium",
      "topic": "Dynamic Equilibrium Analysis",
      "outcomes": [
        "Analyze homogeneous/heterogeneous equilibria, ionic equilibrium, buffer solutions, and solubility equilibria."
      ]
    },
    {
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions",
      "topic": "Electron Transfer Analysis",
      "outcomes": [
        "Classify redox reactions in terms of electron transfer and electrode processes."
      ]
    },
    {
      "unit_name": "Organic Chemistry: Some basic Principles and Techniques",
      "chapter_name": "Some basic Principles and Techniques",
      "topic": "Organic Representation and Mechanisms",
      "outcomes": [
        "Apply nomenclature rules, identify isomerism, and analyze fundamental concepts of organic reaction mechanisms."
      ]
    },
    {
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons",
      "topic": "Hydrocarbon Classification",
      "outcomes": [
        "Differentiate between alkanes, alkenes, alkynes, and aromatic hydrocarbons."
      ]
    }
  ]
}
